import React, {useState, useEffect, useContext} from 'react';

import { CustBarraSuperior } from '../../assets/Customizacoes';
import logo from '../../assets/logo.png';
import ProvedorVariaveisGlobais from '../../contexts/variaveisGlobais';
import { ContextoGlobal } from '../../contexts/variaveisGlobais';

import * as FaIcons from "react-icons/fa";
import { Link } from 'react-router-dom';
const FaBars = <FaIcons.FaBars size = {40} />
const FaTimes = <FaIcons.FaTimes size = {40}/>


function OpcoesColapsaveis(){   

    return (
        <div id='opcoesColapsaveis' className='espacoAntes'>
            <div className='itensOpcoesColapsaveis'>
                Usuário
            </div>
            <select title='Opções'  className='itensOpcoesColapsaveis'>
                <option href='#item'>teste</option>
                <option href='#item'>teste</option>
                <option href='#item'>teste</option>
            </select>
            <Link to='/' className='itensOpcoesColapsaveis'>
                Sair
            </Link>   
        </div>
    )
}

function BarraSuperior(){   

    const {larguraTela, setLarguraTela} = useContext(ContextoGlobal);

    useEffect(() => {
        console.log(larguraTela);
    },[]);

    function setarNovaLargura(){
        setLarguraTela(window.innerWidth);
    }
     
    return(
        <div id='barraSuperior' className='divFlex' onResize={setarNovaLargura}>
            <Link id='campoTitulo' to="/"  >
                <div id='opcoesFixas' >
                    <img
                        alt=""
                        src={logo}
                        width="40"
                        height="40"
                        className="d-inline-block"
                    />
                    <span className='espacoAntes'>
                        {CustBarraSuperior.titulo}
                    </span>   
                </div>
            </Link>
            <OpcoesColapsaveis />
        </div>
    );
}


export default BarraSuperior;
